8052     Value *A;
8053     const APInt *C1, *C2;
8054     ICmpInst::Predicate Pred = I.getPredicate();
8055     if (ICmpInst::isEquality(Pred)) {
8056       // sext(a) & c1 == c2 --> a & c3 == trunc(c2)
8057       // sext(a) & c1 != c2 --> a & c3 != trunc(c2)
8058       if (match(Op0, m_And(m_SExt(m_Value(A)), m_APInt(C1))) &&
