6644 /// Recognize and process idiom involving test for unsigned
6645 /// overflow.
6646 ///
6647 /// The caller has matched a pattern of the form:
6648 ///   I = cmp u (add(zext A, zext B), V
6649 ///   I = cmp u (mul(zext A, zext B), V
6650 /// The function checks if this is a test for overflow and if so replaces
6651 /// addition/multiplication with call to the umul intrinsic or the canonical
6652 /// form of uadd overflow.
6653 ///
6654 /// \param I Compare instruction.
6655 /// \param Val Result of add/mul instruction.  It is one of the arguments of
6656 ///            the compare instruction.  Must be of integer type.
6657 /// \param OtherVal The other argument of compare instruction.
6658 /// \returns Instruction which must replace the compare instruction, NULL if no
6659 ///          replacement required.
6660 static Instruction *processUZExtIdiom(ICmpInst &I, Value *Val,
6661                                       const APInt *OtherVal,
6662                                       InstCombinerImpl &IC) {
6663   // Don't bother doing this transformation for pointers, don't do it for
6664   // vectors.
6665   if (!isa<IntegerType>(Val->getType()))
6666     return nullptr;
6667 
6668   auto *Instr = dyn_cast<Instruction>(Val);
6669   if (!Instr)
6670     return nullptr;
6671 
6672   unsigned Opcode = Instr->getOpcode();
6673   assert(Opcode == Instruction::Add || Opcode == Instruction::Mul);
6674 
6675   auto *LHS = cast<ZExtInst>(Instr->getOperand(0)),
6676        *RHS = cast<ZExtInst>(Instr->getOperand(1));
6677   assert(LHS->getOpcode() == Instruction::ZExt);
6678   assert(RHS->getOpcode() == Instruction::ZExt);
6679   Value *A = LHS->getOperand(0), *B = RHS->getOperand(0);
6680 
6681   // Calculate type and width of the result produced by add/mul.with.overflow.
6682   Type *TyA = A->getType(), *TyB = B->getType();
6683   unsigned WidthA = TyA->getPrimitiveSizeInBits(),
6684            WidthB = TyB->getPrimitiveSizeInBits();
6685   unsigned ResultWidth;
6686   Type *ResultType;
6687   if (WidthB > WidthA) {
6688     ResultWidth = WidthB;
6689     ResultType = TyB;
6690   } else {
6691     ResultWidth = WidthA;
6692     ResultType = TyA;
6693   }
6694 
6695   // In order to replace the original result with a narrower one, all uses must
6696   // ignore upper bits of the result. The number of used low bits must be not
6697   // greater than the width of add or mul.with.overflow.
6698   if (Val->hasNUsesOrMore(2))
6699     for (User *U : Val->users()) {
6700       if (U == &I)
6701         continue;
6702       if (TruncInst *TI = dyn_cast<TruncInst>(U)) {
6703         // Check if truncation ignores bits above ResultWidth.
6704         unsigned TruncWidth = TI->getType()->getPrimitiveSizeInBits();
6705         if (TruncWidth > ResultWidth)
6706           return nullptr;
6707       } else if (BinaryOperator *BO = dyn_cast<BinaryOperator>(U)) {
6708         // Check if AND ignores bits above ResultWidth.
6709         if (BO->getOpcode() != Instruction::And)
6710           return nullptr;
6711         if (ConstantInt *CI = dyn_cast<ConstantInt>(BO->getOperand(1))) {
6712           const APInt &CVal = CI->getValue();
6713           if (CVal.getBitWidth() - CVal.countl_zero() > ResultWidth)
6714             return nullptr;
6715         } else {
6716           // In this case we could have the operand of the binary operation
6717           // being defined in another block, and performing the replacement
6718           // could break the dominance relation.
6719           return nullptr;
6720         }
6721       } else {
6722         // Other uses prohibit this transformation.
6723         return nullptr;
6724       }
6725     }
6726 
6727   // Recognize patterns
6728   switch (I.getPredicate()) {
6729   case ICmpInst::ICMP_UGT: {
6730     // Recognize pattern:
6731     //   val = add/mul(zext A, zext B)
6732     //   cmp ugt val, max
6733     APInt MaxVal = APInt::getMaxValue(ResultWidth);
6734     MaxVal = MaxVal.zext(OtherVal->getBitWidth());
6735     if (MaxVal.eq(*OtherVal))
6736       break; // Recognized
6737     return nullptr;
6738   }
6739 
6740   case ICmpInst::ICMP_ULT: {
6741     // Recognize pattern:
6742     //   val = add/mul(zext A, zext B)
6743     //   cmp ult val, max + 1
6744     APInt MaxVal = APInt::getOneBitSet(OtherVal->getBitWidth(), ResultWidth);
6745     if (MaxVal.eq(*OtherVal))
6746       break; // Recognized
6747     return nullptr;
6748   }
6749 
6750   default:
6751     return nullptr;
6752   }
6753 
6754   InstCombiner::BuilderTy &Builder = IC.Builder;
6755   Builder.SetInsertPoint(Instr);
6756 
6757   // Replace: add/mul(zext A, zext B) --> canonical add/mul + overflow check
6758   Value *ResultA = A, *ResultB = B;
6759   if (WidthA < ResultWidth)
6760     ResultA = Builder.CreateZExt(A, ResultType);
6761   if (WidthB < ResultWidth)
6762     ResultB = Builder.CreateZExt(B, ResultType);
6763 
