6765   Value *OverflowCheck;
6766 
6767   if (Opcode == Instruction::Add) {
6768     // Canonical add overflow check: add + compare
6769     ArithResult = Builder.CreateAdd(ResultA, ResultB, "add");
6770     // Overflow if result < either operand (for unsigned add)
6771     if (I.getPredicate() == ICmpInst::ICMP_ULT)
