6783     OverflowCheck = Builder.CreateExtractValue(Call, 1, "umul.overflow");
6784     if (I.getPredicate() == ICmpInst::ICMP_ULT)
6785       OverflowCheck = Builder.CreateNot(OverflowCheck);
6786   }
6787 
6788   IC.addToWorklist(Instr);
6789 
6790   // Replace uses of the original add/mul result with the new arithmetic result
6791   if (Val->hasNUsesOrMore(2)) {
6792     for (User *U : make_early_inc_range(Val->users())) {
6793       if (U == &I)
6794         continue;
6795       if (TruncInst *TI = dyn_cast<TruncInst>(U)) {
6796         if (TI->getType()->getPrimitiveSizeInBits() == ResultWidth)
