6806         Value *Zext = Builder.CreateZExt(ShortAnd, BO->getType());
6807         IC.replaceInstUsesWith(*BO, Zext);
6808       } else {
6809         llvm_unreachable("Unexpected Binary operation");
6810       }
6811       IC.addToWorklist(cast<Instruction>(U));
6812     }
6813   }
6814 
