6818 /// When performing a comparison against a constant, it is possible that not all
6819 /// the bits in the LHS are demanded. This helper method computes the mask that
6820 /// IS demanded.
6821 static APInt getDemandedBitsLHSMask(ICmpInst &I, unsigned BitWidth) {
6822   const APInt *RHS;
6823   if (!match(I.getOperand(1), m_APInt(RHS)))
6824     return APInt::getAllOnes(BitWidth);
6825 
6826   // If this is a normal comparison, it demands all bits. If it is a sign bit
6827   // comparison, it only demands the sign bit.
6828   bool UnusedBit;
6829   if (isSignBitCheck(I.getPredicate(), *RHS, UnusedBit))
6830     return APInt::getSignMask(BitWidth);
6831 
6832   switch (I.getPredicate()) {
6833   // For a UGT comparison, we don't care about any bits that
6834   // correspond to the trailing ones of the comparand.  The value of these
6835   // bits doesn't impact the outcome of the comparison, because any value
6836   // greater than the RHS must differ in a bit higher than these due to carry.
6837   case ICmpInst::ICMP_UGT:
6838     return APInt::getBitsSetFrom(BitWidth, RHS->countr_one());
6839 
6840   // Similarly, for a ULT comparison, we don't care about the trailing zeros.
6841   // Any value less than the RHS must differ in a higher bit because of carries.
6842   case ICmpInst::ICMP_ULT:
6843     return APInt::getBitsSetFrom(BitWidth, RHS->countr_zero());
6844 
6845   default:
6846     return APInt::getAllOnes(BitWidth);
6847   }
6848 }
